#include <stdio.h>

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, P, X, Y;
        scanf("%d %d %d %d", &N, &P, &X, &Y);
        int sum = 0;
        for (int i = 1; i <= N; ++i) {
            int a; scanf("%d", &a);
            if (i <= P) {
                sum += (a == 1) ? Y : X;
            }
        }
        printf("%d\n", sum);
    }
    return 0;
}

