code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it); P = next(it); X = next(it); Y = next(it)
        total = 0
        for i in range(1, N+1):
            a = next(it)
            if i <= P:
                total += Y if a == 1 else X
        out_lines.append(str(total))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

